I2F.S R2.z, R0.x;
LDC.U64 D0.x, buf14[0];
TEX.F R0, R2, handle(D0.x), ARRAY2D;
MUL.F32 R1, R0, R1;
SEQ.F R0.x, R1.w, {0, 0, 0, 0};
TRUNC.U.CC HC.x, R0;
IF NE.x;
MOV.U.CC RC.x, {1, 0, 0, 0};
KIL NE.x;
ENDIF;
DP3.F32 R0.x, fragment.attrib[1], fragment.attrib[1];
RSQ.F32 R0.x, R0.x;
MUL.F32 R2.xyz, R0.x, fragment.attrib[1];
MOV.F R3.xyz, {0, 0, 0, 0}.x;
MOV.U R2.w, {0, 0, 0, 0}.x;
REP.S ;
LDC.U32 R0.x, buf7[68];
SGE.U.CC HC.x, R2.w, R0;
BRK (NE.x);
MUL.S R0.x, R2.w, {32, 0, 0, 0};
MOV.U R3.w, R0.x;
LDB.F32X4 R0.xyz, sbo_buf13[R3.w + 16];
DP3.F32 R0.x, R2, R0;
MUL.F32 R0.x, R0, {0.5, 0, 0, 0};
ADD.F32.SAT R0.w, R0.x, {0.5, 0, 0, 0}.x;
LDB.F32X4 R4.xyz, sbo_buf13[R3.w];
LDB.F32 R0.x, sbo_buf13[R3.w + 12];
MUL.F32 R4.xyz, R1, R4;
MUL.F32 R0.xyz, R4, R0.x;
MAD.F32 R3.xyz, R0, R0.w, R3;
ADD.U R2.w, R2, {1, 0, 0, 0}.x;
ENDREP;
MOV.U R2.w, {0, 0, 0, 0}.x;
REP.S ;
LDC.U32 R0.x, buf7[64];
SGE.U.CC HC.x, R2.w, R0;
BRK (NE.x);
MUL.S R0.x, R2.w, {32, 0, 0, 0};
MOV.U R3.w, R0.x;
LDB.F32X4 R0.xyz, sbo_buf8[R3.w + 16];
ADD.F32 R0.yzw, R0.xxyz, -fragment.attrib[2].xxyz;
DP3.F32 R0.x, R0.yzww, R0.yzww;
RSQ.F32 R4.x, R0.x;
LDB.F32 R0.x, sbo_buf8[R3.w + 28];
RCP.F32 R4.x, R4.x;
POW.F32 R4.w, R4.x, R0.x;
SGT.F32 R5.x, R0, {9.99999975e-005, 0, 0, 0};
TRUNC.U.CC HC.x, R5;
LDB.F32X4 R4.xyz, sbo_buf8[R3.w];
RCP.F32 R4.w, R4.w;
LDB.F32 R0.x, sbo_buf8[R3.w + 12];
IF NE.x;
MOV.F R3.w, R4;
ELSE;
MOV.F R3.w, {1, 0, 0, 0}.x;
ENDIF;
DP3.F32 R4.w, R0.yzww, R0.yzww;
RSQ.F32 R4.w, R4.w;
MUL.F32 R0.yzw, R4.w, R0;
DP3.F32 R0.y, R2, R0.yzww;
MUL.F32 R0.y, R0, {0.5, 0, 0, 0}.x;
